class SchemaDecoder:
    REQUIRED_COLUMNS = [('column', None), ('start', int), ('length', int)]

    start = None
    length = None
    column = None
    one_based = None

    def __init__(self, header):
        for p, val_type in self.REQUIRED_COLUMNS:
            try:
                if val_type:
